/* DEATH_NOTE_RANK_THRESHOLDS — "DeathNoteRank" case, p._customBlock_WorkbenchStuff("DeathNoteRank",
 * kills, marker), N.js:12237, VERBATIM ternary chain (kills = b, marker = e):
 *   return marker == 7842
 *     ? (kills <    100  ? 0
 *       : kills <    250  ? 1
 *       : kills <   1000  ? 2
 *       : kills <   5000  ? 3
 *       : kills <  25000  ? 4
 *       : kills < 100000  ? 5
 *       : kills < 1000000 ? 7
 *       : 10)
 *     : (kills <   25000    ? 0
 *       : kills <  100000    ? 1
 *       : kills <  250000    ? 2
 *       : kills <  500000    ? 3
 *       : kills < 1000000    ? 4
 *       : kills < 5000000    ? 5
 *       : kills < 100000000  ? 7
 *       : (kills > 1000000000 && riftBonus(3) == 1) ? 20 : 10);
 * GOTCHA: rank 6, 8, and 9 are never returned by either branch — the table jumps 5 -> 7 and, for
 * normal mobs, 7 -> 10 -> (20 if Rift level >= 20 AND kills > 1e9). Transcribed as-is, not a
 * transcription error on our part.
 * The `marker == 7842` branch is a special faster-scaling table used ONLY for "Ninja Twin" kills
 * (NinjaInfo[30] roster, see OverkillQTY category 7 below) — 7842 is a sentinel value, not a real
 * monster ID; it is passed as the `e` argument specifically to select this branch.
 */
export const DEATH_NOTE_RANK_THRESHOLDS = {
  normal: [
    { rank: 0,  killsRequired: 0 },
    { rank: 1,  killsRequired: 25000 },
    { rank: 2,  killsRequired: 100000 },
    { rank: 3,  killsRequired: 250000 },
    { rank: 4,  killsRequired: 500000 },
    { rank: 5,  killsRequired: 1000000 },
    { rank: 7,  killsRequired: 5000000 },
    { rank: 10, killsRequired: 100000000 },
    { rank: 20, killsRequired: 1000000001, requiresRiftBonus3: true }, // strictly > 1e9, AND riftBonus(3); falls back to rank 10 if riftBonus(3) not met
  ],
  ninjaTwins: [ // marker === 7842, e.g. NinjaInfo[30] roster kills
    { rank: 0,  killsRequired: 0 },
    { rank: 1,  killsRequired: 100 },
    { rank: 2,  killsRequired: 250 },
    { rank: 3,  killsRequired: 1000 },
    { rank: 4,  killsRequired: 5000 },
    { rank: 5,  killsRequired: 25000 },
    { rank: 7,  killsRequired: 100000 },
    { rank: 10, killsRequired: 1000000 },
  ],
};

/* MULTIKILL / OVERKILL SEMANTICS — "how many extra kills count per hit" is driven directly by the
 * DeathNoteRank VALUE itself (0,1,2,3,4,5,7,10,20 above): each individual monster's Death Note rank
 * IS its current contribution to account-wide "overkill" (extra simultaneous kills per hit).
 *
 * OverkillQTY(category) — "OverkillQTY" case, N.js:12246-12251, VERBATIM logic: for category 0-6, sum
 * DeathNoteRank(kills, 0) over every mob in DEATH_NOTE_MOBS[category].mobs (kills = each mob's
 * KillsLeft2Advance-derived lifetime kill count, summed account-wide across all characters). For
 * category 7 (no DEATH_NOTE_MOBS entry — this is the special "Ninja Twins" bucket), it instead sums
 * DeathNoteRank(kills, 7842) over every entry in CustomLists.NinjaInfo[30] using Ninja[105][id] as the
 * kill count. Result cached per-category in DNSM.OKqtyZZ[category].
 *
 * MultiKill_perTier — "MultiKill_perTier" case, N.js:12237-12241, VERBATIM: raw = OverkillQTY(floor(
 * CurrentMap/50)) + OverkillQTY(7) + (many unrelated additive bonus sources: alchemy vials, buff
 * bonuses, prayer, chips, star signs, cards, arcade, sailing artifacts, etc — transcribed as-is, not
 * simplified). Then, ONLY once CurrentMap >= 300 (and marker != 8675309, a "give me the raw value"
 * sentinel), `raw` is passed through this diminishing-returns curve to produce the displayed/effective
 * multikill percentage:
 *   result = raw <  20  ? raw                                    // (implicit passthrough below 20)
 *          : raw <  50  ? 20    + (raw -  20) / 1.1
 *          : raw < 100  ? 47.3  + (raw -  50) / 1.5
 *          : raw < 150  ? 80.6  + (raw - 100) / 5
 *          : raw < 200  ? 90.6  + (raw - 150) / 10
 *          : raw < 250  ? 95.6  + (raw - 200) / 20
 *          :              98.14 + (raw - 250) / 50;
 * UNVERIFIED / tangled: the additive "raw" sum draws from ~15 distinct bonus-source function calls
 * (N.js:12237-12239) that were not individually traced here — handed off as the exact expression per
 * the extraction brief, not implemented. The tiered curve breakpoints/slopes above ARE a direct
 * transcription (not tangled), just steep and easy to mistranscribe — double-check against N.js:12239-
 * 12241 before implementing.
 */
export const MULTIKILL_PERTIER_CURVE = [
  { rawMin: 0,   rawMax: 20,  base: 0,     slope: 1 },
  { rawMin: 20,  rawMax: 50,  base: 20,    slope: 1 / 1.1 },
  { rawMin: 50,  rawMax: 100, base: 47.3,  slope: 1 / 1.5 },
  { rawMin: 100, rawMax: 150, base: 80.6,  slope: 1 / 5 },
  { rawMin: 150, rawMax: 200, base: 90.6,  slope: 1 / 10 },
  { rawMin: 200, rawMax: 250, base: 95.6,  slope: 1 / 20 },
  { rawMin: 250, rawMax: Infinity, base: 98.14, slope: 1 / 50 },
];
// result(raw) = tier.base + (raw - tier.rawMin) * tier.slope, for the tier whose [rawMin,rawMax) contains raw.
// Only applied once CurrentMap >= 300; below that, MultiKill_perTier returns the raw additive sum unmodified.

/* ECLIPSE SKULL — CONFIRMED exact mechanic, both from the "eclipseSkulls" case logic (N.js:17872-17877)
 * AND from the in-game tooltip string itself (N.js:14383, verbatim):
 *   "You_can_now_get_Eclipse_Skulls_in_Deathnote,_unlocked_at_1,000,000,000_kills._Eclipse_Skulls_are_
 *    worth_20_points,_and_you_also_get_+5%_Multiplicative_Damage."
 * This CORRECTS the research doc's rough "+5%/maxed" figure: it is not a one-time capped bonus, it is
 * +5% Multiplicative Damage PER Eclipse Skull earned, uncapped, additively stacking (displayed damage
 * bonus = 5 * skullCount, N.js:14382-14383 draws "TOTAL_DAMAGE_BONUS;_+{eclipseSkulls}%" where
 * eclipseSkulls() already returns 5*count — see ECLIPSE_SKULL_DAMAGE_PCT_PER_SKULL below).
 *
 * Mechanic, VERBATIM logic (N.js:17872-17877): for each of 6 categories d in [0,6) — NOTE: only 6, not
 * all 7 DEATH_NOTE_MOBS categories, and NOT the Ninja Twins bucket (category 7) either, so World 7
 * (category 6) monsters can never grant Eclipse Skulls — for every mob in DEATH_NOTE_MOBS[d].mobs, if
 * DeathNoteRank(mobKills, 0) >= 15, increment the account's EclipseSk counter by 1. Since the normal
 * rank table's only value >= 15 is rank 20 (kills > 1e9 AND riftBonus(3)==1, i.e. Rift level >= 20),
 * this is the operative unlock condition per mob line, matching the tooltip's "1,000,000,000 kills".
 * Return value = 5 * EclipseSk (cached; recomputed once per session via a "has EclipseSk key" guard).
 */
export const ECLIPSE_SKULL = {
  unlockKillsPerMobLine: 1_000_000_000, // strictly > 1e9, per DeathNoteRank's `1E9<b` check
  requiresRiftLevelAtLeast: 20, // riftBonus(3): Rift[0] >= 5*(3+1) = 20
  pointsPerSkull: 20, // tooltip: "Eclipse_Skulls_are_worth_20_points"
  multiplicativeDamagePctPerSkull: 5, // tooltip: "+5%_Multiplicative_Damage" per skull, additive across skulls (uncapped)
  eligibleCategories: [0, 1, 2, 3, 4, 5], // DEATH_NOTE_MOBS indices scanned; category 6 (W7) and the Ninja-Twins bucket are EXCLUDED
};

/* riftBonus(b) — m._customBlock_RiftStuff("riftBonus", b), N.js:12177, VERBATIM (gate used by both the
 * rank-20 tier above and Eclipse Skull eligibility):
 *   return Rift[0] >= 5 * (b + 1) ? 1 : 0;
 */
